use askama::Template;
use axum::extract::{Path, State};
use axum::http::{HeaderMap, StatusCode};
use axum::response::{Html, IntoResponse, Redirect, Response};
use axum::Form;
use sqlx::PgPool;
use uuid::Uuid;

use super::auth::AuthenticatedUser;
use crate::domain::{TodoItem, TodoItemId};
use crate::services::todo_service::{
    add_todo, delete_todo, get_todos, toggle_todo_completion, update_todo_title, AddTodoError,
    DeleteTodoError, ToggleTodoError, UpdateTitleError,
};

fn is_htmx_request(headers: &HeaderMap) -> bool {
    headers.contains_key("hx-request")
}

/// Build an HTMX response with an HX-Trigger header that fires an "announce" event
/// for screen reader live regions.
fn htmx_response_with_announce(body: Html<String>, message: &str) -> Response {
    let trigger_json = format!(r#"{{"announce":"{}"}}"#, message);
    (
        [(
            axum::http::header::HeaderName::from_static("hx-trigger"),
            axum::http::HeaderValue::from_str(&trigger_json).unwrap(),
        )],
        body,
    )
        .into_response()
}

/// View model for a single todo item in the template.
pub struct TodoItemView {
    pub id: String,
    pub title: String,
    pub is_completed: bool,
}

impl From<&TodoItem> for TodoItemView {
    fn from(item: &TodoItem) -> Self {
        Self {
            id: item.id().as_uuid().to_string(),
            title: item.title().as_str().to_string(),
            is_completed: item.is_completed(),
        }
    }
}

#[derive(Template)]
#[template(path = "todos.html")]
pub struct TodosTemplate {
    pub todos: Vec<TodoItemView>,
    pub error_message: Option<String>,
}

#[derive(Template)]
#[template(path = "todo_item.html")]
pub struct TodoItemTemplate {
    pub todo: TodoItemView,
}

pub async fn get_todos_page(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
) -> Result<impl IntoResponse, TodosError> {
    let todos = get_todos(&pool, &user_id)
        .await
        .map_err(TodosError::Unexpected)?;

    let todo_views: Vec<TodoItemView> = todos.iter().map(TodoItemView::from).collect();

    let template = TodosTemplate {
        todos: todo_views,
        error_message: None,
    };
    Ok(Html(template.render()?))
}

#[derive(serde::Deserialize)]
pub struct AddTodoForm {
    pub title: String,
}

pub async fn post_todo(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    headers: HeaderMap,
    Form(form): Form<AddTodoForm>,
) -> Result<Response, TodosError> {
    let htmx = is_htmx_request(&headers);

    // Silently ignore empty/whitespace-only submissions per US-5
    if form.title.trim().is_empty() {
        if htmx {
            return Ok(StatusCode::NO_CONTENT.into_response());
        }
        return Ok(Redirect::to("/todos").into_response());
    }

    match add_todo(&pool, user_id.clone(), form.title).await {
        Ok(item) => {
            if htmx {
                let template = TodoItemTemplate {
                    todo: TodoItemView::from(&item),
                };
                let body = template.render().map_err(TodosError::Render)?;
                Ok(htmx_response_with_announce(Html(body), "Todo added"))
            } else {
                Ok(Redirect::to("/todos").into_response())
            }
        }
        Err(AddTodoError::InvalidTitle(title_err)) => {
            let user_facing = match title_err {
                crate::domain::TodoTitleError::Empty => {
                    // Should not reach here due to empty check above, but handle gracefully
                    if htmx {
                        return Ok(StatusCode::NO_CONTENT.into_response());
                    }
                    return Ok(Redirect::to("/todos").into_response());
                }
                crate::domain::TodoTitleError::TooLong { max, .. } => {
                    format!("That title is too long (max {max} characters)")
                }
            };

            let todos = get_todos(&pool, &user_id)
                .await
                .map_err(TodosError::Unexpected)?;
            let todo_views: Vec<TodoItemView> = todos.iter().map(TodoItemView::from).collect();

            let template = TodosTemplate {
                todos: todo_views,
                error_message: Some(user_facing),
            };
            let body = template.render().map_err(TodosError::Render)?;
            Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
        }
        Err(AddTodoError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
    }
}

pub async fn post_toggle_todo(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    headers: HeaderMap,
    Path(todo_id): Path<Uuid>,
) -> Result<Response, TodosError> {
    let htmx = is_htmx_request(&headers);
    let todo_item_id = TodoItemId::from_uuid(todo_id);

    match toggle_todo_completion(&pool, &todo_item_id, &user_id).await {
        Ok(toggled) => {
            if htmx {
                let announce = if toggled.is_completed() {
                    "Todo completed"
                } else {
                    "Todo marked pending"
                };
                let template = TodoItemTemplate {
                    todo: TodoItemView::from(&toggled),
                };
                let body = template.render().map_err(TodosError::Render)?;
                Ok(htmx_response_with_announce(Html(body), announce))
            } else {
                Ok(Redirect::to("/todos").into_response())
            }
        }
        Err(ToggleTodoError::NotFound) => Ok((
            StatusCode::NOT_FOUND,
            Html("<h1>Todo not found</h1>".to_string()),
        )
            .into_response()),
        Err(ToggleTodoError::Unauthorized) => Ok((
            StatusCode::FORBIDDEN,
            Html("<h1>Not authorized</h1>".to_string()),
        )
            .into_response()),
        Err(ToggleTodoError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
    }
}

pub async fn post_delete_todo(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    headers: HeaderMap,
    Path(todo_id): Path<Uuid>,
) -> Result<Response, TodosError> {
    let htmx = is_htmx_request(&headers);
    let todo_item_id = TodoItemId::from_uuid(todo_id);

    match delete_todo(&pool, &todo_item_id, &user_id).await {
        Ok(()) => {
            if htmx {
                Ok(htmx_response_with_announce(
                    Html(String::new()),
                    "Todo deleted",
                ))
            } else {
                Ok(Redirect::to("/todos").into_response())
            }
        }
        Err(DeleteTodoError::NotFound) => Ok((
            StatusCode::NOT_FOUND,
            Html("<h1>Todo not found</h1>".to_string()),
        )
            .into_response()),
        Err(DeleteTodoError::Unauthorized) => Ok((
            StatusCode::FORBIDDEN,
            Html("<h1>Not authorized</h1>".to_string()),
        )
            .into_response()),
        Err(DeleteTodoError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
    }
}

#[derive(Template)]
#[template(path = "edit_todo.html")]
pub struct EditTodoTemplate {
    pub todo_id: String,
    pub current_title: String,
    pub error_message: Option<String>,
}

pub async fn get_edit_todo(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    Path(todo_id): Path<Uuid>,
) -> Result<Response, TodosError> {
    let todo_item_id = TodoItemId::from_uuid(todo_id);

    let item = crate::infrastructure::todo_repository::find_todo_by_id(&pool, &todo_item_id)
        .await
        .map_err(|e| TodosError::Unexpected(anyhow::anyhow!("Database error: {e}")))?;

    match item {
        Some(todo) if todo.user_id() == &user_id => {
            let template = EditTodoTemplate {
                todo_id: todo_id.to_string(),
                current_title: todo.title().as_str().to_string(),
                error_message: None,
            };
            Ok(Html(template.render()?).into_response())
        }
        Some(_) => Ok((
            StatusCode::FORBIDDEN,
            Html("<h1>Not authorized</h1>".to_string()),
        )
            .into_response()),
        None => Ok((
            StatusCode::NOT_FOUND,
            Html("<h1>Todo not found</h1>".to_string()),
        )
            .into_response()),
    }
}

#[derive(serde::Deserialize)]
pub struct EditTodoForm {
    pub title: String,
}

pub async fn post_edit_todo(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    Path(todo_id): Path<Uuid>,
    Form(form): Form<EditTodoForm>,
) -> Result<Response, TodosError> {
    let todo_item_id = TodoItemId::from_uuid(todo_id);

    match update_todo_title(&pool, &todo_item_id, &user_id, form.title.clone()).await {
        Ok(()) => Ok(Redirect::to("/todos").into_response()),
        Err(UpdateTitleError::NotFound) => Ok((
            StatusCode::NOT_FOUND,
            Html("<h1>Todo not found</h1>".to_string()),
        )
            .into_response()),
        Err(UpdateTitleError::Unauthorized) => Ok((
            StatusCode::FORBIDDEN,
            Html("<h1>Not authorized</h1>".to_string()),
        )
            .into_response()),
        Err(UpdateTitleError::InvalidTitle(title_err)) => {
            let user_facing = match title_err {
                crate::domain::TodoTitleError::Empty => "Title cannot be empty".to_string(),
                crate::domain::TodoTitleError::TooLong { max, .. } => {
                    format!("That title is too long (max {max} characters)")
                }
            };
            let template = EditTodoTemplate {
                todo_id: todo_id.to_string(),
                current_title: form.title,
                error_message: Some(user_facing),
            };
            let body = template.render().map_err(TodosError::Render)?;
            Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
        }
        Err(UpdateTitleError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
    }
}

#[derive(Debug, thiserror::Error)]
pub enum TodosError {
    #[error("Failed to render template")]
    Render(#[from] askama::Error),
    #[error(transparent)]
    Unexpected(anyhow::Error),
}

impl IntoResponse for TodosError {
    fn into_response(self) -> Response {
        tracing::error!(error = %self, "Todos error");
        (
            StatusCode::INTERNAL_SERVER_ERROR,
            Html("<h1>Something went wrong</h1>".to_string()),
        )
            .into_response()
    }
}

use crate::helpers::spawn_app;

/// Extract the first todo ID from the page body by finding the toggle form action URL.
fn extract_todo_id(body: &str) -> String {
    // The toggle form action is like: /todos/<uuid>/toggle
    let prefix = "/todos/";
    let suffix = "/toggle";
    let start = body.find(prefix).expect("No toggle form found in body") + prefix.len();
    let remaining = &body[start..];
    let end = remaining
        .find(suffix)
        .expect("No /toggle suffix found in body");
    remaining[..end].to_string()
}

/// Helper: creates a reqwest client with cookie store and no redirect following.
fn authenticated_client() -> reqwest::Client {
    reqwest::Client::builder()
        .cookie_store(true)
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap()
}

/// Helper: register a user and log them in, returning the cookie-jar client.
async fn register_and_login(address: &str, email: &str, password: &str) -> reqwest::Client {
    let client = authenticated_client();

    // Register
    let resp = client
        .post(format!("{address}/register"))
        .form(&[
            ("email", email),
            ("password", password),
            ("password_confirmation", password),
        ])
        .send()
        .await
        .expect("Failed to register");
    assert_eq!(resp.status().as_u16(), 303, "Registration should redirect");

    // Login
    let resp = client
        .post(format!("{address}/login"))
        .form(&[("email", email), ("password", password)])
        .send()
        .await
        .expect("Failed to login");
    assert_eq!(resp.status().as_u16(), 303, "Login should redirect");

    client
}

#[tokio::test]
async fn get_todos_redirects_to_login_when_unauthenticated() {
    let app = spawn_app().await;

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let response = client
        .get(format!("{}/todos", &app.address))
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(
        response.status().as_u16(),
        303,
        "Unauthenticated request should redirect"
    );

    let location = response
        .headers()
        .get("location")
        .expect("Missing Location header")
        .to_str()
        .unwrap();
    assert_eq!(location, "/login", "Should redirect to /login");
}

#[tokio::test]
async fn get_todos_shows_empty_state_for_new_user() {
    let app = spawn_app().await;
    let client = register_and_login(&app.address, "empty@example.com", "securepassword123").await;

    let response = client
        .get(format!("{}/todos", &app.address))
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 200);

    let body = response.text().await.unwrap();

    // Page structure
    assert!(body.contains("My Todos"), "Missing page heading");
    assert!(
        body.contains("My Todos -- Todo List"),
        "Missing descriptive page title"
    );

    // Empty state
    assert!(
        body.contains("No todos yet."),
        "Should show empty state message"
    );

    // Add form is present
    assert!(
        body.contains("<label for=\"title\">New todo</label>"),
        "Missing 'New todo' label"
    );
    assert!(
        body.contains("placeholder=\"What do you need to do?\""),
        "Missing placeholder text"
    );

    // Error container always in DOM (for a11y) but empty on initial load
    assert!(
        body.contains("id=\"add-todo-error\""),
        "Add-todo error element should always be in the DOM with a stable ID"
    );
    assert!(
        body.contains("role=\"alert\""),
        "Add-todo error element should have role=\"alert\""
    );
    assert!(
        body.contains("aria-describedby=\"add-todo-error\""),
        "Title input should have aria-describedby referencing the error element"
    );
    assert!(
        !body.contains("aria-invalid=\"true\""),
        "Should not have aria-invalid on initial load"
    );

    // Logout button is present
    assert!(
        body.contains("Sign out"),
        "Missing sign out button in navigation"
    );

    // List is present but hidden when empty (for HTMX targeting)
    assert!(
        body.contains("<ul") && body.contains("hidden"),
        "Todo list should be in DOM but hidden when there are no todos"
    );
}

